// WF4 v2: Detector de Bajas — semanal
// Step 1: search all active IDs (cheap, just integers)
// Step 2: read 10 at a time, check Syscom
// Step 3: deactivate if not found
const ODOO_URL = "https://ocean-tech.odoo.com/jsonrpc";
const DB = "ocean-tech", UID = 2, PWD = "M1ercole$";
const BATCH = 10;
const helpers = this.helpers;

async function rpc(model,method,args,kw) {
  if(!kw)kw={};
  var r=await helpers.httpRequest({method:"POST",url:ODOO_URL,json:true,
    body:{jsonrpc:"2.0",method:"call",id:Date.now(),
      params:{service:"object",method:"execute_kw",args:[DB,UID,PWD,model,method,args],kwargs:kw}}});
  if(r.error)throw new Error(JSON.stringify(r.error.data||r.error).substring(0,400));
  return r.result;
}

async function getToken() {
  var r=await helpers.httpRequest({method:"POST",url:"https://developers.syscom.mx/oauth/token",
    headers:{"Content-Type":"application/x-www-form-urlencoded"},
    body:"client_id=zq2u2Zr1VFGam5IzAg5UolwmeSnsChP7&client_secret=thdUXtjZunSRT4IB1ascUHIZlWsA5PhtIL9mBWVz&grant_type=client_credentials"});
  return r.access_token;
}

var sd=$getWorkflowStaticData("global");
var body=($input.all()[0]&&$input.all()[0].json&&$input.all()[0].json.body)||($input.all()[0]&&$input.all()[0].json)||{};
if(body.action==="reset"){Object.keys(sd).forEach(function(k){delete sd[k]});return [{json:{_reset:true}}];}

if(!sd.cycle)sd.cycle=0;if(!sd.checked)sd.checked=0;if(!sd.deact)sd.deact=0;if(!sd.errs)sd.errs=0;if(!sd.bajaList)sd.bajaList=[];

// Step 1: Load all IDs on first run of cycle
if(!sd.allIds || sd.allIds.length===0) {
  var allIds = await rpc("product.template","search",[[["active","=",true]]]);
  sd.allIds = allIds;
  sd.idxPos = 0;
  return [{json:{_loaded:true,totalIds:allIds.length}}];
}

var pos = sd.idxPos||0;
if(pos >= sd.allIds.length) {
  // Cycle complete
  var r2={_cycleComplete:true,cycle:sd.cycle+1,checked:sd.checked,deactivated:sd.deact,errors:sd.errs,
    bajas:(sd.bajaList||[]).slice(0,30)};
  sd.allIds=[];sd.idxPos=0;sd.cycle=(sd.cycle||0)+1;sd.checked=0;sd.deact=0;sd.errs=0;sd.bajaList=[];
  return [{json:r2}];
}

// Step 2: Read batch of IDs
var batchIds = sd.allIds.slice(pos, pos+BATCH);
var products;
try {
  products = await rpc("product.template","read",[batchIds],{fields:["id","default_code","name"]});
} catch(e) {
  sd.idxPos = pos+BATCH;
  return [{json:{status:"read_error",error:e.message.substring(0,200)}}];
}

var token;
try{token=await getToken();}catch(e){return [{json:{status:"error",error:"Token: "+e.message}}];}

var deact=0,errs=0;

for(var i=0;i<products.length;i++){
  var prod=products[i];
  var sku=prod.default_code;
  if(!sku||sku===false){continue;}
  sd.checked=(sd.checked||0)+1;

  try{
    var resp=await helpers.httpRequest({method:"GET",
      url:"https://developers.syscom.mx/api/v1/productos?busqueda="+encodeURIComponent(sku)+"&moneda=MXN",
      headers:{Authorization:"Bearer "+token},json:true,options:{timeout:15000}});

    var found=false;
    var items=resp.productos||[];
    for(var j=0;j<items.length;j++){
      if(items[j].modelo===sku){found=true;break;}
    }

    if(!found){
      await rpc("product.template","write",[[prod.id],{active:false}]);
      deact++;sd.deact=(sd.deact||0)+1;
      if((sd.bajaList||[]).length<100){
        sd.bajaList.push({sku:sku,name:String(prod.name||"").substring(0,40)});
      }
    }
  }catch(e){
    errs++;sd.errs=(sd.errs||0)+1;
  }
}

sd.idxPos=pos+BATCH;

return [{json:{_summary:true,pos:pos,batch:products.length,deact:deact,errs:errs,
  global:{checked:sd.checked,deact:sd.deact,errs:sd.errs,remaining:sd.allIds.length-sd.idxPos,pct:Math.round(sd.idxPos*100/sd.allIds.length)}
}}];

